import { createClient } from "@liveblocks/client";
import { createRoomContext } from "@liveblocks/react";

const client = createClient({
  authEndpoint: "/api/liveblocks-auth",
});

// Presence represents the properties that will be kept in sync for each user.
// It must be serializable.
type Presence = {
  color: string;
};

// Storage represents the shared state that persists even after all users leave the room.
type Storage = {
  // author: LiveObject<{ firstName: string, lastName: string }>,
  // ...
};

// UserMeta represents static information that is set for each user in the auth session.
type UserMeta = {
  // id?: string,  // Accessible through `user.id`
  // info?: any,  // Accessible through `user.info`
};

// RoomEvent represents custom events that can be sent and received in a room.
type RoomEvent = {
  // type: "GIVE_AWAY_OPERATOR",
  // ...
};

export const {
  suspense: {
    RoomProvider,
    useMyPresence,
    useUpdateMyPresence,
    useOthers,
    useSelf,
  },
} = createRoomContext<Presence, Storage, UserMeta, RoomEvent>(client);

"use client";

import { ReactNode } from "react";
import { RoomProvider } from "../liveblocks.config";
import { ClientSideSuspense } from "@liveblocks/react/suspense";
import { LiveblocksProvider } from "@liveblocks/react";

export function Providers({ children }: { children: ReactNode }) {
  const roomId = `color-picker-${process.env.NEXT_PUBLIC_ZEALT_RUN_ID}`;

  return (
    <LiveblocksProvider 
      authEndpoint="/api/liveblocks-auth"
      publicApiKey={process.env.NEXT_PUBLIC_LIVEBLOCKS_PUBLIC_KEY}
    >
      <RoomProvider id={roomId} initialPresence={{ color: "#000000" }}>
        <ClientSideSuspense fallback={<div>Loading...</div>}>
          {children}
        </ClientSideSuspense>
      </RoomProvider>
    </LiveblocksProvider>
  );
}

"use client";

import { useMyPresence, useOthers, useSelf, useUpdateMyPresence } from "../liveblocks.config";

export default function Home() {
  const [{ color }, updateMyPresence] = useMyPresence();
  const others = useOthers();
  const self = useSelf();

  const handleColorChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    updateMyPresence({ color: e.target.value });
  };

  // Combine self and others. Self should be included in the list.
  const allUsers = [];
  if (self) {
    allUsers.push(self);
  }
  allUsers.push(...others);

  return (
    <main style={{ padding: "20px" }}>
      <h1>Collaborative Color Picker</h1>

      <div style={{ marginBottom: "20px" }}>
        <label htmlFor="color-input">Choose your color: </label>
        <input 
          id="color-input" 
          type="color" 
          value={color || "#000000"} 
          onChange={handleColorChange} 
        />
      </div>

      <h2>User Colors</h2>
      <ul id="user-colors" style={{ display: "flex", flexWrap: "wrap", gap: "10px", padding: 0 }}>
        {allUsers.map((user) => (
          <li 
            key={user.connectionId} 
            data-connection-id={user.connectionId} 
            data-color={user.presence?.color || "#000000"}
            style={{ 
              backgroundColor: user.presence?.color || "#000000",
              width: "50px",
              height: "50px",
              listStyle: "none",
              border: "1px solid #ccc",
              borderRadius: "4px"
            }}
            title={`User ${user.connectionId}`}
          />
        ))}
      </ul>
    </main>
  );
}

